/**
 * Temporary one-shot route: deploys EmberBridge to the EMBR chain from
 * WITHIN the server process so it bypasses external RPC timeouts caused by
 * mining load on the shared stateManager.
 *
 * DELETE THIS FILE after EmberBridge is deployed to production.
 */

import { Router } from "express";
import { ethers } from "ethers";
import { chain } from "../lib/chain";

const router = Router();

// EmberBridge compiled bytecode (contracts/emberswap/artifacts/…/EmberBridge.json)
const EMBR_BRIDGE_BYTECODE =
  "";

// ABI for the constructor only
const CONSTRUCTOR_ABI = ["constructor(address relayer)"];

let deployLock = false;

router.post("/admin/deploy-ember-bridge", async (req, res) => {
  if (deployLock) {
    return res.status(409).json({ error: "Deploy already in progress" });
  }
  deployLock = true;

  try {
    const privateKey = process.env.DEPLOYER_PRIVATE_KEY;
    const relayer = process.env.RELAYER_ADDRESS ?? "0x9954146017aCE1994BC076243Ed49EC28C64D77B";

    if (!privateKey) {
      return res.status(500).json({ error: "DEPLOYER_PRIVATE_KEY not set" });
    }

    const wallet = new ethers.Wallet(privateKey);
    const iface = new ethers.Interface(CONSTRUCTOR_ABI);
    const encodedArgs = iface.encodeDeploy([relayer]);
    const deployData = EMBR_BRIDGE_BYTECODE + encodedArgs.slice(2); // strip 0x from args

    // Compute tx hash deterministically (ethers v6)
    const walletInfo = await chain.getWallet(wallet.address as `0x${string}`);
    const nonce = walletInfo.nonce;
    const GAS_LIMIT = 2_000_000n;
    const GAS_PRICE = 1_000_000_000n;
    const CHAIN_ID = 7773n;

    const txObj = {
      nonce,
      gasLimit: GAS_LIMIT,
      gasPrice: GAS_PRICE,
      to: undefined as undefined,
      value: 0n,
      data: deployData,
      chainId: CHAIN_ID,
      type: 0,
    };

    const signed = await wallet.signTransaction(txObj);

    // Parse the hash from the signed tx
    const txHash = ethers.keccak256(signed) as `0x${string}`;
    const from = wallet.address as `0x${string}`;

    console.log(`[admin-deploy] Submitting EmberBridge deployment tx ${txHash}`);

    // Submit INTERNALLY — no HTTP round-trip, no timeout risk.
    await chain.submitRawEVMTransaction({
      hash: txHash,
      from,
      to: null,
      value: "0",
      data: deployData as `0x${string}`,
      gasLimit: GAS_LIMIT.toString(),
      nonce: BigInt(nonce),
    });

    console.log(`[admin-deploy] Tx in mempool, waiting for confirmation...`);

    // Poll for confirmation (up to 5 min)
    const deadline = Date.now() + 5 * 60 * 1000;
    let contractAddress: string | null = null;
    while (Date.now() < deadline) {
      await new Promise((r) => setTimeout(r, 3000));
      const tx = await chain.getTransaction(txHash);
      if (tx && tx.status !== "pending") {
        if (tx.status === "failed") {
          return res.status(500).json({ error: "Deploy tx failed", tx });
        }
        contractAddress = tx.contractAddress;
        break;
      }
    }

    if (!contractAddress) {
      return res.status(504).json({ error: "Timed out waiting for confirmation", txHash });
    }

    console.log(`[admin-deploy] EmberBridge deployed to ${contractAddress}`);
    return res.json({ success: true, contractAddress, txHash });
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    console.error("[admin-deploy] Error:", msg);
    return res.status(500).json({ error: msg });
  } finally {
    deployLock = false;
  }
});

export default router;
